    type Err = eyre::Error;

    fn from_str(s: &str) -> Result<Self> {
        let short = unalias_backend(s).to_string();
        let explicit = if let Some((prefix, _)) = short.split_once(':') {
            BackendType::guess(prefix) != BackendType::Unknown
        } else {
            false
        };
